import { createClient } from '@/utils/supabase/server'
import Hero from '@/components/Hero'

async function getProfile() {
  const supabase = await createClient()
  const { data } = await supabase
    .from('Profile')
    .select('*')
    .single()
  return data
}

export default async function Home() {
  const profile = await getProfile()

  return (
    <main className="min-h-screen bg-[#0a0a0a] selection:bg-teal-500/30 selection:text-white">
      <Navbar />
      
      <Hero profile={profile} />

      {/* Other sections will go here */}
      <section className="py-20 px-6 max-w-7xl mx-auto text-center opacity-50">
        <p className="text-sm tracking-widest text-gray-500 uppercase">
          More sections (Projects, About, Contact) are coming soon...
        </p>
      </section>
    </main>
  )
}
